--- a/internals/daemon/api_services_test.go
+++ b/internals/daemon/api_services_test.go
@@ -16,8 +16,11 @@ package daemon

 import (
 	"bytes"
+	"context"
 	"encoding/json"
+	"fmt"
 	"io/ioutil"
